// Evidence: httpsts-worked-http-server-ts-request-authority-proxy-2
// Competency: httpsts-worked-http-server-ts-request-authority-proxy-2.
// Case 7417: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: remove one trusted proxy hop and recompute authority from the socket boundary.
function worked_http_server_ts_request_authority_proxy_2(host: string, forwardedHost: string, trustedProxy: boolean): { authority: string; allowed: boolean } {
  const authority = trustedProxy && forwardedHost.length > 0 ? forwardedHost : host;
  const normalized = authority.toLowerCase();
  const allowed = normalized === "api.example.test" || normalized === "api.example.test:443";
  return { authority: normalized, allowed };
}

